CREATE DATABASE IF NOT EXISTS anna_seed_farm; USE anna_seed_farm; CREATE TABLE users(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100),username VARCHAR(50) UNIQUE,password VARCHAR(255)); CREATE TABLE categories(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(150)); CREATE TABLE products(id INT AUTO_INCREMENT PRIMARY KEY,category_id INT,name VARCHAR(200),price DECIMAL(10,2),image VARCHAR(255),description TEXT,status TINYINT DEFAULT 1);